mapper.select:
SELECT id, status, host_id, cert_start_time, cert_end_time
FROM challenges
WHERE id = #{challengeId}

SELECT id, status
FROM challenge_participants
WHERE challenge_id = #{challengeId}
  AND user_id = #{userId}

mapper.update:
UPDATE certification_posts
SET certification_status = 'APPROVED',
    approval_type = #{approvalType}
WHERE id = #{postId}
  AND certification_status = 'PENDING'

UPDATE certification_posts SET certification_status = 'APPROVED', approval_type = 'AUTO' WHERE id IN
#{postId}
AND certification_status = 'PENDING'

mapper.select:
SELECT challenge_participant_id AS participant_id, COUNT(DISTINCT (created_at::date)) AS success_count FROM certification_posts WHERE challenge_participant_id IN
#{participantId}
AND certification_status = 'APPROVED' GROUP BY challenge_participant_id

SELECT p.id AS post_id, p.user_id AS author_id, u.nickname AS author_nickname, cp.challenge_id AS challenge_id, p.certification_image_url AS thumbnail_url, p.contents, p.like_count, p.comment_count, p.created_at FROM certification_posts p JOIN challenge_participants cp ON cp.id = p.challenge_participant_id JOIN users u ON u.id = p.user_id
cp.challenge_id = #{challengeId} AND p.certification_status = 'PENDING' AND p.deleted_at IS NULL
AND p.id < #{cursor}
ORDER BY p.id DESC LIMIT #{size}

SELECT p.id AS certification_id, c.id AS challenge_id, c.title AS challenge_title, p.user_id AS author_id, u.nickname AS author_nickname, p.certification_image_url AS thumbnail_url, p.created_at AS certified_at FROM certification_posts p JOIN challenge_participants cp ON cp.id = p.challenge_participant_id JOIN challenges c ON c.id = cp.challenge_id JOIN users u ON u.id = p.user_id WHERE p.id IN
#{postId}
AND p.deleted_at IS NULL -- 삭제된 인증글 조회 채팅 공유 메시지에서 제외

SELECT p.id AS post_id, p.user_id AS author_id, u.nickname AS author_nickname, cp.challenge_id AS challenge_id, p.certification_image_url AS thumbnail_url, p.contents, p.like_count, p.comment_count, p.created_at FROM certification_posts p JOIN challenge_participants cp ON cp.id = p.challenge_participant_id JOIN challenges c ON c.id = cp.challenge_id JOIN users u ON u.id = p.user_id
p.deleted_at IS NULL
AND p.certification_status = 'APPROVED'
AND (p.like_count < #{cursorLike} OR (p.like_count = #{cursorLike} AND p.id < #{cursor}))
AND p.id < #{cursor}
AND cp.challenge_id = #{challengeId}
AND p.user_id = #{targetUserId}
AND c.feed_visibility = 'PUBLIC'
AND ( c.feed_visibility = 'PUBLIC' OR cp.challenge_id IN ( SELECT vp.challenge_id FROM challenge_participants vp WHERE vp.user_id = #{viewerId} AND vp.status = 'ACTIVE' ) )
AND p.user_id = #{viewerId}
AND p.created_at::date = CURRENT_DATE
ORDER BY p.like_count DESC, p.id DESC
ORDER BY p.id DESC
LIMIT #{size}

mapper.update:
UPDATE certification_posts
SET like_count = like_count + 1
WHERE id = #{postId}

UPDATE certification_posts
SET like_count = GREATEST(like_count - 1, 0)
WHERE id = #{postId}
